import{_ as o,o as s,c as i,ae as r}from"./chunks/framework.C8MNLDzb.js";const m=JSON.parse('{"title":"宋词名句","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/mingju/ji/宋词.md","filePath":"docs/sucai/mingju/ji/宋词.md"}'),n={name:"docs/sucai/mingju/ji/宋词.md"};function l(g,t,a,e,_,c){return s(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="宋词名句" tabindex="-1">宋词名句 <a class="header-anchor" href="#宋词名句" aria-label="Permalink to &quot;宋词名句&quot;">​</a></h1><ol><li><strong>明月几时有？把酒问青天。</strong> —— 明月什么时候才有？我端起酒杯询问青天。（苏轼《水调歌头》）</li><li><strong>但愿人长久，千里共婵娟。</strong> —— 只希望人能平安健康，即使相隔千里也能共同欣赏这美好的月光。（苏轼《水调歌头》）</li><li><strong>大江东去，浪淘尽，千古风流人物。</strong> —— 大江的水一直向东流去，波浪淘洗尽了千古以来的英雄豪杰。（苏轼《念奴娇·赤壁怀古》）</li><li><strong>人生如梦，一尊还酹江月。</strong> —— 人生不过像一场梦，我举起酒杯洒在江里祭奠那轮明月。（苏轼《念奴娇·赤壁怀古》）</li><li><strong>十年生死两茫茫，不思量，自难忘。</strong> —— 十年来生死相隔，你我茫茫然不互通消息，即使不去刻意想念，自然也难以遗忘。（苏轼《江城子》）</li><li><strong>莫听穿林打叶声，何妨吟啸且徐行。</strong> —— 不必在意那穿过树林打在叶子上的雨声，姑且一边吟诗长啸一边慢慢走吧。（苏轼《定风波》）</li><li><strong>竹杖芒鞋轻胜马，谁怕？一蓑烟雨任平生。</strong> —— 拄着竹杖穿着草鞋走路比骑马还轻快，怕什么？一身蓑衣在风雨中度过一生也任其自然。（苏轼《定风波》）</li><li><strong>春色三分，二分尘土，一分流水。</strong> —— 春天的景色如果分作三分，二分化为尘土，一分落入流水。（苏轼《水龙吟》）</li><li><strong>缺月挂疏桐，漏断人初静。</strong> —— 一弯残月挂在稀疏的梧桐树上，壶水断滴时人们才安静下来。（苏轼《卜算子》）</li><li><strong>莫道不消魂，帘卷西风，人比黄花瘦。</strong> —— 别说不会消磨神魂，西风吹起帘子，人比那秋天的菊花还要消瘦。（李清照《醉花阴》）</li><li><strong>寻寻觅觅，冷冷清清，凄凄惨惨戚戚。</strong> —— 反复地寻求搜索，眼前只有冷冷清清，凄凉悲伤一起涌来。（李清照《声声慢》）</li><li><strong>生当作人杰，死亦为鬼雄。</strong> —— 活着的时候要当人中的豪杰，死了也要做鬼中的英雄。（李清照《夏日绝句》）</li><li><strong>至今思项羽，不肯过江东。</strong> —— 直到现在仍然思念项羽，不肯逃回江东。（李清照《夏日绝句》）</li><li><strong>三十功名尘与土，八千里路云和月。</strong> —— 三十年来功名微薄如尘土，八千里路途艰难伴随云和月。（岳飞《满江红》）</li><li><strong>怒发冲冠，凭栏处、潇潇雨歇。</strong> —— 我愤怒得头发冲起了帽子，凭靠着栏杆外面，急雨刚刚停住。（岳飞《满江红》）</li><li><strong>莫等闲、白了少年头，空悲切。</strong> —— 不要虚度光阴，等闲视之，等到少年头变白时，只能徒然悲伤。（岳飞《满江红》）</li><li><strong>壮志饥餐胡虏肉，笑谈渴饮匈奴血。</strong> —— 满怀壮志仇恨，吃敌人的肉，谈谈笑笑渴了喝敌人的血。（岳飞《满江红》）</li><li><strong>众里寻他千百度，蓦然回首，那人却在，灯火阑珊处。</strong> —— 在人群中寻找她千百次，突然回头一看，她却站在灯火零落的地方。（辛弃疾《青玉案·元夕》）</li><li><strong>醉里挑灯看剑，梦回吹角连营。</strong> —— 醉酒中挑亮灯芯观看宝剑，梦醒后回到相连接的军营。（辛弃疾《破阵子》）</li><li><strong>了却君王天下事，赢得生前身后名。可怜白发生！</strong> —— 完成君王统一天下的大业，获取生前死后的功名。可怜头发已经白了！（辛弃疾《破阵子》）</li></ol>',2)])])}const u=o(n,[["render",l]]);export{m as __pageData,u as default};
